from typing import List


def bisect_left(a: List[int], x: int) -> int:
    lo, hi = 0, len(a) - 1  # bug: should allow insert at len(a)
    while lo < hi:
        mid = (lo + hi) // 2
        if a[mid] < x:
            lo = mid + 1
        else:
            hi = mid
    if lo < len(a) and a[lo] < x:
        return lo + 1
    return lo

